Debounce delays invoking a function until after it stops being called for a specified time, which helps throttle frequent events like resize or input.

function debounce(fn, delay) {
  let timeoutId;
  return function(...args) {
    const context = this;
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn.apply(context, args), delay);
  };
}

// Example: log window size 200ms after resizing stops
const onResize = debounce(() => {
  console.log('Resized to:', window.innerWidth, 'x', window.innerHeight);
}, 200);

window.addEventListener('resize', onResize);

// Example: debounce search input
const searchInput = document.querySelector('#search');
const search = debounce((q) => {
  console.log('Searching for:', q);
  // fetch(`/api/search?q=${encodeURIComponent(q)}`).then(...)
}, 300);

searchInput.addEventListener('input', (e) => search(e.target.value));
